function loadProducts() {
  const saved = localStorage.getItem('aeronexus_products');
  if (saved) {
    try { STATE.products = JSON.parse(saved); } catch { STATE.products = [...PLACEHOLDER_PRODUCTS]; }
  } else {
    STATE.products = [...PLACEHOLDER_PRODUCTS];
  }
  STATE.filteredProducts = [...STATE.products];
}

function saveProducts() {
  localStorage.setItem('aeronexus_products', JSON.stringify(STATE.products));
}

const $ = (sel, ctx = document) => ctx.querySelector(sel);
const $$ = (sel, ctx = document) => Array.from(ctx.querySelectorAll(sel));

function showToast(msg, type = 'success') {
  const container = $('#toast-container');
  const icon = type === 'success'
    ? `<svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.5"><polyline points="20 6 9 17 4 12"/></svg>`
    : `<svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.5"><line x1="18" y1="6" x2="6" y2="18"/><line x1="6" y1="6" x2="18" y2="18"/></svg>`;
  const toast = document.createElement('div');
  toast.className = `toast ${type}`;
  toast.style.color = type === 'success' ? 'var(--teal-bright)' : 'var(--red-accent)';
  toast.innerHTML = icon + `<span style="color:var(--text-primary)">${msg}</span>`;
  container.appendChild(toast);
  setTimeout(() => toast.remove(), 3500);
}

function openModal(id) {
  const overlay = $(`#${id}`);
  if (overlay) { overlay.classList.add('open'); document.body.style.overflow = 'hidden'; }
}
function closeModal(id) {
  const overlay = $(`#${id}`);
  if (overlay) { overlay.classList.remove('open'); document.body.style.overflow = ''; }
}

const TYPE_META = {
  template: { label: 'Template', badgeClass: 'badge-template', icon: getFileIcon('template') },
  ebook:    { label: 'E-Book',   badgeClass: 'badge-ebook',    icon: getFileIcon('ebook') },
  video:    { label: 'Video',    badgeClass: 'badge-video',    icon: getFileIcon('video') },
  image:    { label: 'Image',    badgeClass: 'badge-image',    icon: getFileIcon('image') },
};

function getFileIcon(type) {
  const icons = {
    template: `<svg width="36" height="36" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.5"><rect x="4" y="2" width="16" height="20" rx="2"/><line x1="8" y1="7" x2="16" y2="7"/><line x1="8" y1="11" x2="16" y2="11"/><line x1="8" y1="15" x2="13" y2="15"/></svg>`,
    ebook:    `<svg width="36" height="36" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.5"><path d="M2 3h6a4 4 0 0 1 4 4v14a3 3 0 0 0-3-3H2z"/><path d="M22 3h-6a4 4 0 0 0-4 4v14a3 3 0 0 1 3-3h7z"/></svg>`,
    video:    `<svg width="36" height="36" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.5"><polygon points="23 7 16 12 23 17 23 7"/><rect x="1" y="5" width="15" height="14" rx="2"/></svg>`,
    image:    `<svg width="36" height="36" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.5"><rect x="3" y="3" width="18" height="18" rx="2"/><circle cx="8.5" cy="8.5" r="1.5"/><polyline points="21 15 16 10 5 21"/></svg>`,
  };
  return icons[type] || icons.template;
}

function renderProducts() {
  const grid = $('#products-grid');
  if (!grid) return;
  const products = STATE.filteredProducts;
  if (products.length === 0) {
    grid.innerHTML = `<div class="empty-state" style="grid-column:1/-1">
      <svg width="48" height="48" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.5">
        <circle cx="11" cy="11" r="8"/><path d="m21 21-4.35-4.35"/>
      </svg><p>NO CONTENT FOUND</p></div>`;
    return;
  }
  grid.innerHTML = products.map(p => {
    const meta  = TYPE_META[p.type] || TYPE_META.template;
    const price = p.price === 0
      ? '<span class="product-price free">FREE</span>'
      : `<span class="product-price">$${p.price.toFixed(2)}</span>`;
    const thumb = p.placeholder
      ? `<div class="thumb-placeholder">${meta.icon}<span>PLACEHOLDER — COMING SOON</span></div>`
      : (p.thumb ? `<img src="${p.thumb}" alt="${p.title}" loading="lazy">` : `<div class="thumb-placeholder">${meta.icon}</div>`);
    const reviews = getReviews(p.id);
    const avg = reviews.length ? (reviews.reduce((s,r) => s + r.rating, 0) / reviews.length) : 0;
    const starsHtml = renderStarsHtml(avg);
    return `<div class="product-card" data-id="${p.id}">
      <div class="product-thumb">
        ${thumb}
        <span class="type-badge ${meta.badgeClass}">${meta.label}</span>
      </div>
      <div class="product-body">
        <div class="product-title">${escHtml(p.title)}</div>
        <div class="product-rating" onclick="openReviewsModal('${p.id}')" style="cursor:pointer" title="View reviews">
          <div class="stars">${starsHtml}</div>
          <span class="rating-count">${reviews.length > 0 ? avg.toFixed(1) + ' (' + reviews.length + ')' : 'No reviews yet'}</span>
        </div>
        <div class="product-desc">${escHtml(p.description)}</div>
        <div class="product-meta">
          ${price}
          <span class="product-size">${p.fileSize !== '—' ? p.fileSize : 'N/A'}</span>
        </div>
        <button class="btn btn-ghost product-download-btn" onclick="handleDownload('${p.id}')" ${p.placeholder ? 'disabled title="Coming soon"' : ''}>
          <svg width="13" height="13" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.5">
            <path d="M21 15v4a2 2 0 0 1-2 2H5a2 2 0 0 1-2-2v-4"/><polyline points="7 10 12 15 17 10"/><line x1="12" y1="15" x2="12" y2="3"/>
          </svg>
          ${p.placeholder ? 'COMING SOON' : (p.price === 0 ? 'DOWNLOAD FREE' : 'GET FILE')}
        </button>
      </div>
    </div>`;
  }).join('');
}

function escHtml(str) {
  const d = document.createElement('div');
  d.textContent = str;
  return d.innerHTML;
}

function applyFilters() {
  let results = [...STATE.products];
  if (STATE.activeFilter !== 'all') {
    results = results.filter(p => p.type === STATE.activeFilter);
  }
  if (STATE.searchQuery.trim()) {
    const q = STATE.searchQuery.toLowerCase();
    results = results.filter(p =>
      p.title.toLowerCase().includes(q) || p.description.toLowerCase().includes(q)
    );
  }
  STATE.filteredProducts = results;
  renderProducts();
  updateCount();
}

function updateCount() {
  const el = $('#result-count');
  if (el) el.textContent = `${STATE.filteredProducts.length} item${STATE.filteredProducts.length !== 1 ? 's' : ''}`;
}

function setFilter(type) {
  STATE.activeFilter = type;
  $$('.filter-btn').forEach(b => {
    b.classList.toggle('active', b.dataset.filter === type);
  });
  applyFilters();
}

function handleDownload(id) {
  const p = STATE.products.find(x => x.id === id);
  if (!p || p.placeholder) { showToast('Content coming soon!', 'error'); return; }
  if (p.price === 0) {
    if (!p.fileName) { showToast('File not attached yet.', 'error'); return; }
    showToast(`Preparing "${p.title}" for download…`);
    return;
  }
  // Paid product — open payment modal
  openPayModal(p);
}

