function getReviews(productId) {
  const stored = JSON.parse(localStorage.getItem('aero_reviews_' + productId) || 'null');
  const seeds  = SEED_REVIEWS[productId] || [];
  return stored ? [...seeds, ...stored] : seeds;
}

function saveReview(productId, review) {
  const stored = JSON.parse(localStorage.getItem('aero_reviews_' + productId) || '[]');
  stored.push(review);
  localStorage.setItem('aero_reviews_' + productId, JSON.stringify(stored));
}

function renderStarsHtml(avg, size) {
  let html = '';
  for (let i = 1; i <= 5; i++) {
    if (i <= Math.round(avg)) {
      html += `<span class="star">&#9733;</span>`;
    } else {
      html += `<span class="star empty">&#9733;</span>`;
    }
  }
  return html;
}

let currentReviewProductId = null;
let pickedStars = 0;

function openReviewsModal(productId) {
  currentReviewProductId = productId;
  const p = STATE.products.find(x => x.id === productId);
  if (!p) return;
  const reviews = getReviews(productId);
  const avg = reviews.length ? (reviews.reduce((s,r) => s + r.rating, 0) / reviews.length) : 0;

  $('#reviews-product-title').textContent = p.title;
  $('#reviews-avg-score').textContent = reviews.length ? avg.toFixed(1) : '—';
  $('#reviews-avg-stars').innerHTML = renderStarsHtml(avg);
  $('#reviews-count-label').textContent = reviews.length + ' REVIEW' + (reviews.length !== 1 ? 'S' : '');

  const list = $('#reviews-list');
  if (reviews.length === 0) {
    list.innerHTML = '<p style="text-align:center;color:var(--text-muted);font-family:var(--font-mono);font-size:0.72rem;padding:20px">No reviews yet. Be the first!</p>';
  } else {
    list.innerHTML = reviews.slice().reverse().map(r => `
      <div class="review-item">
        <div class="review-header">
          <div class="review-avatar">${r.name[0].toUpperCase()}</div>
          <div class="review-meta">
            <div class="review-name">${escHtml(r.name)}</div>
            <div class="review-date">${r.date}</div>
          </div>
          <div class="stars">${renderStarsHtml(r.rating)}</div>
        </div>
        <div class="review-text">${escHtml(r.text)}</div>
      </div>
    `).join('');
  }

  // Reset form
  pickedStars = 0;
  $('#review-name-input').value = '';
  $('#review-text-input').value = '';
  updateStarPicker(0);

  openModal('reviews-modal');
}

function updateStarPicker(val) {
  $$('.star-pick').forEach(s => {
    s.classList.toggle('active', parseInt(s.dataset.val) <= val);
  });
}

function submitReview() {
  const name = $('#review-name-input').value.trim();
  const text = $('#review-text-input').value.trim();
  if (!name) { showToast('Please enter your name.', 'error'); return; }
  if (!pickedStars) { showToast('Please select a star rating.', 'error'); return; }
  if (!text) { showToast('Please write a short review.', 'error'); return; }
  const today = new Date().toISOString().slice(0,10);
  saveReview(currentReviewProductId, { name, rating: pickedStars, text, date: today });
  showToast('Review submitted! Thank you.');
  openReviewsModal(currentReviewProductId);
  renderProducts();
}

/* ========== RECOMMENDED PRODUCTS ========== */
const TYPE_EMOJI = { ebook:'📚', template:'📄', video:'🎥', image:'🖼️' };

function renderRecommended() {
  const container = $('#recommended-scroll');
  if (!container) return;
  // Pick up to 8: shuffle products and show them
  const shuffled = [...STATE.products].sort(() => Math.random() - 0.5).slice(0, 8);
  if (shuffled.length === 0) { container.innerHTML = '<p style="color:var(--text-muted);font-family:var(--font-mono);font-size:0.72rem">No products yet.</p>'; return; }
  container.innerHTML = shuffled.map(p => {
    const reviews = getReviews(p.id);
    const avg = reviews.length ? (reviews.reduce((s,r) => s + r.rating, 0) / reviews.length) : 0;
    const priceHtml = p.price === 0
      ? '<span class="rec-price free">FREE</span>'
      : `<span class="rec-price">$${p.price.toFixed(2)}</span>`;
    const meta = TYPE_META[p.type] || TYPE_META.template;
    return `<div class="rec-card" onclick="handleDownload('${p.id}')">
      <div class="rec-thumb">
        ${p.thumb ? `<img src="${p.thumb}" alt="${p.title}" style="width:100%;height:100%;object-fit:cover">` : `<span>${TYPE_EMOJI[p.type] || '📄'}</span>`}
        <span class="type-badge ${meta.badgeClass}" style="top:8px;left:8px;font-size:0.55rem">${meta.label}</span>
      </div>
      <div class="rec-body">
        <div class="rec-tag">${reviews.length > 0 ? '&#9733; ' + avg.toFixed(1) + ' (' + reviews.length + ')' : 'New'}</div>
        <div class="rec-title">${escHtml(p.title)}</div>
        ${priceHtml}
      </div>
    </div>`;
  }).join('');
}

