/* ========== HERO SEARCH ========== */
function heroSearchGo() {
  const q = $('#hero-search-input').value.trim();
  if (!q) return;
  STATE.searchQuery = q;
  const navInput = $('#nav-search-input');
  if (navInput) navInput.value = q;
  applyFilters();
  closeHeroSuggestions();
  document.getElementById('store').scrollIntoView({ behavior: 'smooth' });
}

function closeHeroSuggestions() {
  const el = $('#hero-suggestions');
  if (el) el.classList.remove('open');
}

document.addEventListener('DOMContentLoaded', () => {
  // Star picker events
  $$('.star-pick').forEach(s => {
    s.addEventListener('click', () => {
      pickedStars = parseInt(s.dataset.val);
      updateStarPicker(pickedStars);
    });
    s.addEventListener('mouseover', () => updateStarPicker(parseInt(s.dataset.val)));
    s.addEventListener('mouseout',  () => updateStarPicker(pickedStars));
  });

  // Hero search live suggestions
  const heroInput = $('#hero-search-input');
  const herySugg  = $('#hero-suggestions');
  if (heroInput && herySugg) {
    heroInput.addEventListener('input', () => {
      const q = heroInput.value.trim().toLowerCase();
      if (!q) { closeHeroSuggestions(); return; }
      const matches = STATE.products.filter(p =>
        p.title.toLowerCase().includes(q) || p.description.toLowerCase().includes(q)
      ).slice(0, 6);
      if (matches.length === 0) {
        herySugg.innerHTML = '<div class="no-results-suggestion">No resources found — try another keyword</div>';
      } else {
        herySugg.innerHTML = matches.map(p => {
          const priceLabel = p.price === 0 ? '<span class="suggestion-price free">FREE</span>' : `<span class="suggestion-price">$${p.price.toFixed(2)}</span>`;
          return `<div class="suggestion-item" onclick="selectSuggestion('${p.id}', '${escHtml(p.title).replace(/'/g,"\\'")}')">
            <span class="suggestion-icon">${TYPE_EMOJI[p.type] || '📄'}</span>
            <div class="suggestion-text">
              <div class="suggestion-title">${escHtml(p.title)}</div>
              <div class="suggestion-type">${p.type}</div>
            </div>
            ${priceLabel}
          </div>`;
        }).join('');
      }
      herySugg.classList.add('open');
    });
    heroInput.addEventListener('keydown', e => { if (e.key === 'Enter') heroSearchGo(); if (e.key === 'Escape') closeHeroSuggestions(); });
    document.addEventListener('click', e => { if (!$('#hero-search-box').contains(e.target)) closeHeroSuggestions(); });
  }
});

function selectSuggestion(id, title) {
  closeHeroSuggestions();
  const p = STATE.products.find(x => x.id === id);
  if (!p) return;
  // Set search to exact title, filter, scroll
  const heroInput = $('#hero-search-input');
  if (heroInput) heroInput.value = title;
  STATE.searchQuery = title;
  const navInput = $('#nav-search-input');
  if (navInput) navInput.value = title;
  applyFilters();
  document.getElementById('store').scrollIntoView({ behavior: 'smooth' });
}


const AERONEXUS_PHONE = '254719353490';
const AERONEXUS_PHONE_DISPLAY = '+254 719 353 490';
// Approximate KES per USD rate (update as needed)
const USD_TO_KES = 130;

let currentPayProduct = null;
let currentPayMethod  = 'mpesa';

function openPayModal(product) {
  currentPayProduct = product;
  currentPayMethod  = 'mpesa';

  $('#pay-product-name').textContent  = product.title;
  $('#pay-product-price').textContent = `$${product.price.toFixed(2)}`;

  const kesAmount = Math.ceil(product.price * USD_TO_KES);
  $('#mpesa-kes-amount').textContent = `KES ${kesAmount.toLocaleString()}`;
  $('#mpesa-amount-copy').dataset.amount = String(kesAmount);

  // Reference = short product title slug
  const ref = 'AERO-' + product.title.toUpperCase().replace(/[^A-Z0-9]/g, '').slice(0, 10);
  $('#mpesa-ref').textContent = ref;

  // Reset method selection
  selectPayMethod('mpesa');

  const overlay = $('#payment-modal');
  overlay.classList.add('open');
  document.body.style.overflow = 'hidden';
}

function closePayModal() {
  $('#payment-modal').classList.remove('open');
  document.body.style.overflow = '';
}

function selectPayMethod(method) {
  currentPayMethod = method;
  ['mpesa','whatsapp'].forEach(m => {
    $('#method-' + m).classList.toggle('selected', m === method);
  });
  $('#mpesa-panel').classList.toggle('visible', method === 'mpesa');
  $('#whatsapp-panel').classList.toggle('visible', method === 'whatsapp');
}

function copyText(text, btn) {
  navigator.clipboard.writeText(text).then(() => {
    const orig = btn.textContent;
    btn.textContent = '✓ COPIED';
    btn.style.color = 'var(--teal-bright)';
    setTimeout(() => { btn.textContent = orig; btn.style.color = ''; }, 1800);
  }).catch(() => {
    showToast('Copy failed — please copy manually.', 'error');
  });
}

function copyMpesaAmount(btn) {
  copyText(btn.dataset.amount || $('#mpesa-kes-amount').textContent.replace('KES ','').replace(',',''), btn);
}

function confirmMpesaPayment() {
  if (!currentPayProduct) return;
  const kesAmount = Math.ceil(currentPayProduct.price * USD_TO_KES);
  const ref = $('#mpesa-ref').textContent;
  const msg = encodeURIComponent(
    `Hello AERONEXUS 👋\n\nI have sent M-Pesa payment for:\n📦 *${currentPayProduct.title}*\n💰 KES ${kesAmount.toLocaleString()}\n🔖 Ref: ${ref}\n\nPlease find my M-Pesa confirmation screenshot attached. Kindly send the file. Thank you!`
  );
  window.open(`https://wa.me/${AERONEXUS_PHONE}?text=${msg}`, '_blank');
}

function openWhatsAppOrder() {
  if (!currentPayProduct) return;
  const msg = encodeURIComponent(
    `Hello AERONEXUS 👋\n\nI'd like to purchase:\n📦 *${currentPayProduct.title}*\n💵 Price: $${currentPayProduct.price.toFixed(2)} USD\n\nPlease send me payment details. Thank you!`
  );
  window.open(`https://wa.me/${AERONEXUS_PHONE}?text=${msg}`, '_blank');
}

