let pendingFile = null;

function handleFileDrop(e) {
  e.preventDefault();
  $('#upload-zone').classList.remove('drag-over');
  const file = e.dataTransfer?.files[0] || e.target.files[0];
  if (file) selectFile(file);
}

function selectFile(file) {
  pendingFile = file;
  $('#upload-file-name').value = file.name;
  $('#upload-file-size').value = formatSize(file.size);
  showToast(`File selected: ${file.name}`);
}

function formatSize(bytes) {
  if (bytes < 1024) return bytes + ' B';
  if (bytes < 1048576) return (bytes / 1024).toFixed(1) + ' KB';
  return (bytes / 1048576).toFixed(1) + ' MB';
}

function handleUploadSubmit(e) {
  e.preventDefault();
  const title = $('#upload-title').value.trim();
  const desc  = $('#upload-desc').value.trim();
  const type  = $('#upload-type').value;
  const price = parseFloat($('#upload-price').value) || 0;
  if (!title) { showToast('Title is required.', 'error'); return; }
  const id = 'aero-' + Date.now();
  if (pendingFile && pendingFile.type.startsWith('image/')) {
    const reader = new FileReader();
    reader.onload = ev => finaliseUpload(id, title, desc, type, price, pendingFile, ev.target.result);
    reader.readAsDataURL(pendingFile);
  } else {
    finaliseUpload(id, title, desc, type, price, pendingFile, null);
  }
}

function finaliseUpload(id, title, desc, type, price, file, thumb) {
  const product = { id, type, title, description: desc, price,
    fileSize: file ? formatSize(file.size) : '—',
    fileName: file ? file.name : null,
    thumb, placeholder: false, uploadedAt: new Date().toISOString() };
  if (STATE.editingId) {
    const idx = STATE.products.findIndex(p => p.id === STATE.editingId);
    if (idx !== -1) STATE.products[idx] = { ...STATE.products[idx], ...product, id: STATE.editingId };
    STATE.editingId = null;
  } else {
    STATE.products.unshift(product);
  }
  saveProducts(); applyFilters(); renderAdminTable(); resetUploadForm();
  showToast(`"${title}" saved successfully!`);
  pendingFile = null;
}

function resetUploadForm() {
  $('#upload-form').reset();
  $('#upload-file-name').value = '';
  $('#upload-file-size').value = '';
  pendingFile = null;
  STATE.editingId = null;
  $('#upload-submit-btn').textContent = 'PUBLISH FILE';
}

function deleteProduct(id) {
  if (!confirm('Remove this item from the store?')) return;
  STATE.products = STATE.products.filter(p => p.id !== id);
  saveProducts(); applyFilters(); renderAdminTable();
  showToast('Item removed.');
}

function editProduct(id) {
  const p = STATE.products.find(x => x.id === id);
  if (!p) return;
  STATE.editingId = id;
  $('#upload-title').value = p.title;
  $('#upload-desc').value  = p.description;
  $('#upload-type').value  = p.type;
  $('#upload-price').value = p.price;
  $('#upload-submit-btn').textContent = 'UPDATE FILE';
  $('#admin-panel').scrollIntoView({ behavior: 'smooth' });
  showToast('Editing: ' + p.title);
}

function renderAdminTable() {
  const tbody = $('#admin-table-body');
  if (!tbody) return;
  if (STATE.products.length === 0) {
    tbody.innerHTML = `<tr><td colspan="5" class="empty-state"><p>NO ITEMS YET. UPLOAD YOUR FIRST FILE ABOVE.</p></td></tr>`;
    return;
  }
  tbody.innerHTML = STATE.products.map(p => {
    const meta = TYPE_META[p.type] || TYPE_META.template;
    return `<tr>
      <td><span class="file-name">${escHtml(p.title)}</span></td>
      <td><span class="type-badge ${meta.badgeClass}" style="position:static">${meta.label}</span></td>
      <td>${p.price === 0 ? 'Free' : '$' + p.price.toFixed(2)}</td>
      <td>${p.placeholder ? '<em style="color:var(--text-muted)">placeholder</em>' : (p.fileName || '—')}</td>
      <td><div class="file-actions">
        <button class="btn btn-ghost" style="padding:5px 10px;font-size:0.65rem" onclick="editProduct('${p.id}')">EDIT</button>
        <button class="btn btn-danger" style="padding:5px 10px;font-size:0.65rem" onclick="deleteProduct('${p.id}')">REMOVE</button>
      </div></td>
    </tr>`;
  }).join('');
}

function setupNav() {
  window.addEventListener('scroll', () => {
    const nav = $('#navbar');
    if (nav) nav.classList.toggle('scrolled', window.scrollY > 40);
  });
}

function hideLoader() {
  const loader = $('#loader');
  if (!loader) return;
  setTimeout(() => {
    loader.style.opacity = '0';
    loader.style.transition = 'opacity 0.5s ease';
    setTimeout(() => loader.remove(), 500);
  }, 1800);
}

