// Override handleUploadSubmit to use API
async function handleUploadSubmit(e) {
  e.preventDefault();
  const title = $('#upload-title').value.trim();
  const desc  = $('#upload-desc').value.trim();
  const type  = $('#upload-type').value;
  const price = parseFloat($('#upload-price').value) || 0;
  if (!title) { showToast('Title is required.', 'error'); return; }

  const btn = $('#upload-submit-btn');
  if (btn) btn.textContent = 'UPLOADING…';

  try {
    if (STATE.editingId) {
      // Update existing product metadata
      const { product } = await AeroAPI.Products.update(STATE.editingId, { title, description: desc, type, price });
      // If a new file was also selected, upload it
      if (pendingFile) {
        if (pendingFile.type.startsWith('image/')) {
          await AeroAPI.Upload.uploadThumb(STATE.editingId, pendingFile);
        } else {
          await AeroAPI.Upload.uploadFile(pendingFile, {});
        }
      }
      STATE.editingId = null;
      showToast(`"${product.title}" updated successfully!`);
    } else if (pendingFile) {
      // Upload file + create product in one shot
      await AeroAPI.Upload.uploadFile(pendingFile, { title, description: desc, type, price });
      showToast(`"${title}" published successfully!`);
    } else {
      // No file — create product metadata only
      await AeroAPI.Products.create({ title, description: desc, type, price, fileSize: '—', placeholder: true });
      showToast(`"${title}" saved (no file attached).`);
    }
    // Refresh product list from API
    await loadProducts();
    applyFilters();
    renderAdminTable();
    resetUploadForm();
  } catch (err) {
    showToast(err.message || 'Upload failed.', 'error');
  } finally {
    if (btn) btn.textContent = STATE.editingId ? 'UPDATE FILE' : 'PUBLISH FILE';
    pendingFile = null;
  }
}

// Override deleteProduct to use API
async function deleteProduct(id) {
  if (!confirm('Remove this item from the store?')) return;
  try {
    await AeroAPI.Products.remove(id);
    STATE.products = STATE.products.filter(p => p.id !== id);
    applyFilters(); renderAdminTable();
    showToast('Item removed.');
  } catch (err) {
    showToast(err.message || 'Delete failed.', 'error');
  }
}

